content.css:
.html-content-viewer {
  width: 100%;
  height: 100%;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
}
.hcv-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
}
.hcv-loading-dots {
  display: flex;
  gap: 6px;
}
.hcv-loading-dots span {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #0078d4;
  animation: hcv-dot-pulse 1.4s ease-in-out infinite;
}
.hcv-loading-dots span:nth-child(2) {
  animation-delay: 0.2s;
}
.hcv-loading-dots span:nth-child(3) {
  animation-delay: 0.4s;
}
@keyframes hcv-dot-pulse {
  0%,
  80%,
  100% {
    opacity: 0.25;
    transform: scale(0.75);
  }
  40% {
    opacity: 1;
    transform: scale(1);
  }
}
.hcv-error {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 100%;
  height: 100%;
  color: #d83b01;
  font-size: 13px;
  padding: 16px;
  text-align: center;
}
.hcv-placeholder {
  display: flex;
  align-items: flex-start;
  justify-content: flex-start;
  width: 100%;
  height: 100%;
  padding: 24px;
  box-sizing: border-box;
  overflow: auto;
}
.hcv-placeholder .hcv-placeholder-inner {
  text-align: left;
  max-width: 380px;
}
.hcv-placeholder .hcv-placeholder-title {
  font-size: 18px;
  font-weight: 600;
  color: #333;
  margin-bottom: 2px;
}
.hcv-placeholder .hcv-placeholder-link {
  font-size: 13px;
  color: #0078d4;
  cursor: pointer;
  display: inline-block;
  margin-bottom: 14px;
}
.hcv-placeholder .hcv-placeholder-link:hover {
  text-decoration: underline;
}
.hcv-placeholder .hcv-placeholder-desc {
  font-size: 13px;
  color: #555;
  line-height: 1.5;
  margin-bottom: 16px;
}
.hcv-placeholder .hcv-placeholder-features-title {
  font-size: 11px;
  font-weight: 600;
  color: #444;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}
.hcv-placeholder .hcv-placeholder-features {
  list-style: none;
  padding: 0;
  margin: 0 0 14px 0;
}
.hcv-placeholder .hcv-placeholder-features li {
  font-size: 12px;
  color: #666;
  padding: 3px 0;
  padding-left: 14px;
  position: relative;
  line-height: 1.4;
}
.hcv-placeholder .hcv-placeholder-features li::before {
  content: "\2022";
  color: #0078d4;
  position: absolute;
  left: 0;
}
.hcv-placeholder .hcv-placeholder-features li strong {
  color: #444;
  font-weight: 600;
}
.hcv-content {
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  overflow: auto;
  word-wrap: break-word;
}
.hcv-content h1,
.hcv-content h2,
.hcv-content h3,
.hcv-content h4,
.hcv-content h5,
.hcv-content h6 {
  margin-top: 0.5em;
  margin-bottom: 0.3em;
}
.hcv-content p {
  margin: 0.4em 0;
}
.hcv-content table {
  border-collapse: collapse;
  width: 100%;
}
.hcv-content table th,
.hcv-content table td {
  border: 1px solid #ddd;
  padding: 6px 8px;
  text-align: left;
}
.hcv-content table th {
  background-color: rgba(0, 0, 0, 0.05);
  font-weight: 600;
}
.hcv-content a {
  color: #0078d4;
  text-decoration: underline;
}
.hcv-content img {
  max-width: 100%;
  height: auto;
}
.hcv-content pre {
  background-color: rgba(0, 0, 0, 0.04);
  padding: 8px;
  border-radius: 4px;
  overflow-x: auto;
}
.hcv-content code {
  font-family: Consolas, "Courier New", monospace;
  font-size: 0.9em;
}
.hcv-content blockquote {
  border-left: 3px solid #ddd;
  margin: 0.5em 0;
  padding: 4px 12px;
  color: #555;
}
.hcv-warning {
  padding: 8px 12px;
  margin-bottom: 8px;
  border-radius: 4px;
  font-size: 12px;
  line-height: 1.4;
}
.hcv-warning .hcv-warning-icon {
  font-size: 14px;
}
.hcv-warning-red {
  background: #fde7e9;
  border: 1px solid #d83b01;
  color: #a80000;
}
.hcv-warning-red .hcv-warning-icon {
  color: #d83b01;
}
.hcv-warning-yellow {
  background: #fff4ce;
  border: 1px solid #ffb900;
  color: #6b5900;
}
.hcv-warning-yellow .hcv-warning-icon {
  color: #ffb900;
}
.hcv-warning-blue {
  background: #d4edff;
  border: 1px solid #0078d4;
  color: #004578;
}
.hcv-warning-icon-only {
  position: absolute;
  top: 6px;
  right: 6px;
  font-size: 18px;
  cursor: default;
  z-index: 10;
  opacity: 0.85;
}
.hcv-warning-icon-only:hover {
  opacity: 1;
}
.hcv-warning-icon-red {
  color: #d83b01;
}
.hcv-warning-icon-yellow {
  color: #ffb900;
}
.hcv-desktop-license-badge {
  position: absolute;
  top: 4px;
  left: 4px;
  width: 18px;
  height: 18px;
  font-size: 11px;
  line-height: 18px;
  text-align: center;
  border-radius: 50%;
  background: rgba(0, 0, 0, 0.06);
  opacity: 0.35;
  cursor: default;
  z-index: 10;
}
.hcv-desktop-license-badge:hover {
  opacity: 0.7;
}
.hcv-license-overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 200;
  opacity: 0;
  transition: opacity 4s ease-in;
}
.hcv-license-overlay.hcv-license-visible {
  opacity: 1;
}
.hcv-license-backdrop {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(255, 255, 255, 0.8);
}
.hcv-license-inner {
  position: absolute;
  top: 12px;
  left: 12px;
  text-align: left;
  max-width: 280px;
  padding: 16px 20px;
  background: #ffffff;
  border-radius: 6px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
}
.hcv-license-title {
  font-size: 16px;
  font-weight: 600;
  color: #333;
  margin-bottom: 8px;
}
.hcv-license-text {
  font-size: 12px;
  color: #555;
  line-height: 1.5;
  margin-bottom: 12px;
}
.hcv-license-link {
  font-size: 13px;
  color: #0078d4;
  cursor: pointer;
  font-weight: 600;
}
.hcv-license-link:hover {
  text-decoration: underline;
}
